import React from 'react'
import { Helmet } from 'react-helmet'

function Contact() {
  var tat = ""
  var hello = `javascript${tat}:sendemail()`
  return (
    <div>
      <Helmet><title>Contact Us - Deeptam Research Foundation</title></Helmet>
      <div class="container">

        <div class="row">

          <div class="col-xl-8 offset-xl-2 py-5">
            <h1>Contact Us</h1>
            <p class="lead mt-4">Stuck at a problem. Feal free to contact with us and share the problem with us.
              By
              just fill up this Contact Us form.</p>
            <form action={hello} method="POST" id="form">
              <div class="messages"></div>
              <div class="controls">
                <div class="row">
                  <div class="col-md-12">
                    <div class="form-group">
                      <label for="form_name">Full Name <span class="text-danger">*</span></label>
                      <input spellcheck="false" id="Name" name="Name" type="text" class="form-control"
                        placeholder="Please enter your full name *" required="required"
                        data-error="Firstname is required." />
                    </div>
                  </div>
                </div>
                <div class="row">
                  <div class="col-md-12">
                    <div class="form-group">
                      <label for="form_email">Email <span class="text-danger">*</span></label>
                      <input spellcheck="false" id="Email" name="Email" type="email"
                        class="form-control" placeholder="Please enter your email *"
                        required="required" data-error="Valid email is required." />
                    </div>
                  </div>
                </div>
                <div class="row">
                  <div class="col-md-12">
                    <div class="form-group">
                      <label for="form_message">Message <span class="text-danger">*</span></label>
                      <textarea spellcheck="false" id="message" name="message"
                        class="form-control message" placeholder="Message for me *" rows="5"
                        required="required" data-error="Please, leave us a message."></textarea>
                    </div>
                  </div>
                  <div class="col-md-12">
                    <button class="button btn btn-success btn-send">Submit</button>
                    <span id="load"></span>
                  </div>
                </div>
              </div>
            </form>
          </div>
        </div>
      </div>

      <div class="modal fade" id="myModal" role="dialog">
        <div class="modal-dialog">
          <div class="modal-content">
            <div class="modal-header" id="modal-header" style={{padding:'35px 50px'}}>
              <h4><span class="glyphicon glyphicon-lock"></span> Contact Us</h4>
              <button type="button" style={{outline: 'none'}} class="close" data-dismiss="modal">&times;</button>
            </div>
            <div class="modal-body" id="message_sent" style={{padding:'40px 50px'}}>
              <h5 id="message_sent_msg">...</h5>
            </div>
            <div class="modal-footer">
              <button type="submit" class="btn btn-danger btn-default pull-left" data-dismiss="modal"><span
                class="glyphicon glyphicon-remove"></span> Close</button>
            </div>
          </div>

        </div>
      </div>
    </div>
  )
}

export default Contact
