import React from "react";
import Data from "../Data/VideosData";
import { Route, Switch, Link, useLocation } from "react-router-dom";
import FourHundFour from "../Components/FourHundFour";
import { Helmet } from 'react-helmet'
import TutorialsData from "../Data/TutorialsData";

// Categories Data starts
function Tutorials() {
  let mylocate = useLocation()
  function Prev() {
    for (let index = 0; index < Data.length; index++) {
      if (Data[index].To === mylocate.pathname) {
        let prev = Data[index].Sno - 1
        prev = prev.toString()
        for (let previous = 0; previous < Data.length; previous++) {
          if (Data[previous].Sno === prev) {
            if (Data[previous].Categories === Data[index].Categories) {
              console.log(Data[previous].To)
              return Data[previous].To
            }
          }
        }
      }
    }
  }
  function Next() {
    for (let index = 0; index < Data.length; index++) {
      if (Data[index].To === mylocate.pathname) {
        let prev = Number(Data[index].Sno) + 1
        prev = prev.toString()
        for (let previous = 0; previous < Data.length; previous++) {
          if (Data[previous].Sno === prev) {
            if (Data[previous].Categories === Data[index].Categories) {
              console.log(Data[previous].To)
              return Data[previous].To
            }
            else {
            }
          }
        }
      }
    }
  }
  function Disable() {
    for (let index = 0; index < Data.length; index++) {
      if (Data[index].To === mylocate.pathname) {
        for (let indexex = 0; indexex < Data.length; indexex++) {
          if (Data[index].Categories === Data[indexex].Categories) {
            let next = Number(Data[index].Sno)
            for (let indexes = 0; indexes < Data.length; indexes++) {
              if (Data[indexes].Categories === Data[index].Categories) {
                var element = Data[indexes];
              }
            }
            if (element.Sno.indexOf(next) > -1) {
              return "d"
            }
            else {
              return ""
            }
          }
        }
      }
    }
  }
  function DisablePrev() {
    for (let index = 0; index < Data.length; index++) {
      if (Data[index].To === mylocate.pathname) {
        let prev = Number(Data[index].Sno)
        if (prev === 1) {
          return "d"
        }
        else {
          return ""
        }
      }
    }
  }
  function categoriesdata(val) {
    return (
      <>
        <div className="card mx-auto my-2 p-2 align-items-center" style={{ width: '18rem' }}>
          <img src={val.img} alt={val.Name} className="rounded-circle img-fluid" />
          <div className="card-body">
            <h5 className="card-title text-center">{val.Name}</h5>
            <p className="card-text text-center">{val.desc}
            </p>
            <Link to={val.To} className="btn btn-primary d-block">Start Learning</Link>
          </div>
        </div>
      </>
    );
  }

  function Category() {
    return (
      <>
        <Helmet>
          <title>Programming Tutorials - Deeptam Research Foundation</title>
          <meta name="description" content="Get Many softwares by its categories - SoftwareMess" />
        </Helmet>
        <div className="container">
          <div className="row mb-4 mt-3">
            {TutorialsData.map(categoriesdata)}
          </div>
        </div>
      </>
    );
  }

  function catedetect() {
    for (let index = 0; index < Data.length; index++) {
      if (
        Data[index].To === mylocate.pathname
      ) {
        return (Data[index].Categories)
      }
    }
  }
  function ncard(val) {
    if (val.Categories === catedetect()) {
      return (
        <>
          <div style={{ paddingTop: '5px', paddingBottom: '5px' }}>
            <h2><span>{val.Sno + "."} </span>
              <Link to={val.To} className="text-dark">
                {val.Name}
              </Link>
            </h2>
            <p>{val.desc}</p>
            <Link to={val.To} className="btn btn-outline-danger">
              Start Learning
            </Link>
            <hr />
          </div>
        </>
      )
    }
  }
  function data(val) {
    return (
      <Route exact path={val.To}>
        <Helmet><title>{`${val.Sno}. ${val.Name} - Deeptam Research Foundation`}</title></Helmet>
        <div className="iframe_and_Player">
          <div style={{
            position: 'relative',
            overflow: 'hidden',
            width: '100%',
            paddingTop: '56.25%'
          }}>
            <iframe width="100%" title={val.Name} height="1000px" src={val.Iframe} frameborder="0"
              allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture"
              allowfullscreen style={{
                position: 'absolute',
                top: 0,
                left: 0,
                bottom: 0,
                right: 0,
                width: '100%',
                height: '100%'
              }}></iframe>
          </div>
        </div>
        <ul id="myTab" role="tablist" className="nav nav-tabs">
          <li role="presentation" className="nav-item"><a id="overview-tab" data-toggle="tab" href="#source-code" role="tab"
            aria-controls="overview" aria-selected="true" className="nav-link active text-dark">Source Code</a></li>
          <li role="presentation" className="nav-item"><a id="announcements-tab" data-toggle="tab" href="#player"
            role="tab" aria-controls="announcements" aria-selected="false" className="nav-link text-dark">Player</a></li>
        </ul>
        <div id="myTabContent" className="tab-content">
          <div id="source-code" role="tabpanel" aria-labelledby="overview-tab" className="tab-pane fade mx-4 mt-3 active show">
            <div className="clearfix py-0 px-0">
              <h2 className="my-2">{val.Name}</h2>
              <div className="contentBox">
                <div>
                  {val.content}
                </div>
              </div>
            </div>
          </div>
          <div id="player" role="tabpanel" aria-labelledby="announcements-tab" className="tab-pane fade mx-4 mt-3">
            <div>
              {Data.map(ncard)}
            </div>
          </div>
        </div>
        <div className="container-fluid mb-3 mt-3">
          <div className="row mx-2">
            <div>
              <Link to={Prev()}><button id="prev" className="btn btn-danger" disabled={DisablePrev()}>&larr; Previous</button></Link>
            </div>
            <div className="col-md-0 ml-auto">
              <Link to={Next()}><button id="next" className="btn btn-danger" disabled={Disable()}>Next &rarr;</button></Link>
            </div>
          </div>
        </div>
      </Route>
    )
  }
  return (
    <>
      <Switch>
        <Route exact path="/videos" component={Category} />
        {Data.map(data)}
        <>
          <Helmet>
            <title>404 Page Not Found</title>
          </Helmet>
          <Route component={FourHundFour}></Route>
          <Route path="/404.html" component={FourHundFour}></Route>
        </>
      </Switch>
    </>
  );
}

export default Tutorials;