import React from "react";
import Btobtn from './Components/Btobtn'
import { Route, Switch, HashRouter } from "react-router-dom";
import Home from "./Components/Home";
import './css/index.css'
import Search from "./Components/Search";
import "./css/software.css";
import ScrollToTop from "./Components/ScrollToTop";
import Nav from "./Components/Nav";
import Footer from "./Components/Footer";
import Tutorials from "./Softwares/Tutorials";
import Sidebar from './Components/SideBar';
import Contact from './Components/Contact.js'

const App = () => {
  const [shouldRefresh, setShouldRefresh] = React.useState(false);
  React.useEffect(() => {
    const id = setTimeout(
      () => setShouldRefresh(true),
      10
    );
    return () => clearTimeout(id);
  }, []);

  return (
    <HashRouter forceRefresh={shouldRefresh}>
      <Btobtn/>
      <Nav />
      <ScrollToTop />
      <Switch>
        <Route exact path="/"><Sidebar/><Home /></Route>
        <Route exact path="/contact"><Sidebar/><Contact /></Route>
        <Route exact path="/search/" component={Search} />
        <Route exact path="/search/:search" component={Search} />
        <Tutorials />
      </Switch>
      <Footer />
    </HashRouter>
  );
}

export default App;